\label{thm:equality-sym-lidskii-inequalities}
    Let $A, B \in \mathbb{P}_{2n}(\mathbb{R})$ and $1 \leq i_1 < \cdots < i_k \leq n$ be any distinct indices. 
    The following statements are equivalent:
    \begin{itemize}
	\item [(i)] 
		The equality in \eqref{eq:sym-lidskii-inequality} holds, that is,
		\begin{align}\label{eq:sym-lidskii-equality}
    			\sum_{j=1}^{k} d_{i_j}(A+B) = \sum_{j=1}^{k} d_{i_j}(A)+\sum_{j=1}^{k} d_{j}(B).
		\end{align}
	\item [(ii)] 
		For all $t \in [0,1]$, we have
		\begin{align}\label{eq:sym:lidskii-linear}
          		\sum_{j=1}^{k} d_{i_j}(A+tB) = \sum_{j=1}^{k} d_{i_j}(A)+t\sum_{j=1}^{k} d_{j}(B).
		\end{align} 
	\item [(iii)] 
		There exist positive numbers $0=a_0<a_1<\cdots < a_r=1$ such that the following properties hold:
		for all $\ell \in \{1,\ldots, r\}$ and $t \in (a_{\ell-1}, a_\ell)$, there exists $M(t) \in \operatorname{Sp}(2n, 2k)$ 	such that the columns of $M(t)$ form symplectic eigenvector pairs of $A+t B$ corresponding to the symplectic eigenvalues $d_{i_1}(A+t B), \ldots, d_{i_k}(A+t B)$, and it satisfies 
		\begin{align}
           		\operatorname{Tr}\! \left[M(t)^T A M(t) \right]
				&= 2\sum_{j=1}^{k} d_{i_j}(A), \label{eq1:conditions-equality-sym-lidskii} \\
          		\operatorname{Tr}\!\left[M(t)^T B M(t) \right]
				&=2\sum_{j=1}^{k} d_{j}(B). \label{eq2:conditions-equality-sym-lidskii}
		\end{align} 
    \end{itemize}

